import{_ as e,o as l,c as a,a4 as n}from"./chunks/framework._in6GHBg.js";const y=JSON.parse('{"title":"化学实验详解","description":"","frontmatter":{},"headers":[],"relativePath":"chemistry/Chem-Learn-Detail-005-化学实验详解-V1.0-20260405.md","filePath":"chemistry/Chem-Learn-Detail-005-化学实验详解-V1.0-20260405.md"}'),i={name:"chemistry/Chem-Learn-Detail-005-化学实验详解-V1.0-20260405.md"};function s(d,t,r,g,o,h){return l(),a("div",null,[...t[0]||(t[0]=[n(`<h1 id="化学实验详解" tabindex="-1">化学实验详解 <a class="header-anchor" href="#化学实验详解" aria-label="Permalink to &quot;化学实验详解&quot;">​</a></h1><p><strong>板块5：基本操作 + 分离提纯 + 物质检验 + 实验探究</strong></p><hr><h2 id="学习策略" tabindex="-1">学习策略 <a class="header-anchor" href="#学习策略" aria-label="Permalink to &quot;学习策略&quot;">​</a></h2><p><strong>化学实验是「实践检验真理」的体现</strong>：</p><ul><li>高考实验题源于课本，又高于课本</li><li>既考操作，又考原理，还考设计</li><li>重视「为什么这样做」，不只是「怎么做」</li></ul><p><strong>学习方法</strong>：</p><ol><li><strong>熟悉课本实验</strong>：高考题都源于课本</li><li><strong>掌握基本操作</strong>：分离提纯、气体制备、物质检验</li><li><strong>理解实验原理</strong>：每步操作的科学依据</li><li><strong>总结答题模板</strong>：实验探究题的回答套路</li></ol><hr><h2 id="第一章-化学实验基本操作" tabindex="-1">第一章：化学实验基本操作 <a class="header-anchor" href="#第一章-化学实验基本操作" aria-label="Permalink to &quot;第一章：化学实验基本操作&quot;">​</a></h2><h3 id="_1-1-常用仪器" tabindex="-1">1.1 常用仪器 <a class="header-anchor" href="#_1-1-常用仪器" aria-label="Permalink to &quot;1.1 常用仪器&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">仪器</th><th style="text-align:left;">用途</th><th style="text-align:left;">注意事项</th></tr></thead><tbody><tr><td style="text-align:center;">试管</td><td style="text-align:left;">少量试剂反应</td><td style="text-align:left;">加热时液体不超过1/3</td></tr><tr><td style="text-align:center;">烧杯</td><td style="text-align:left;">较多量试剂反应、溶解</td><td style="text-align:left;">加热时垫石棉网</td></tr><tr><td style="text-align:center;">烧瓶</td><td style="text-align:left;">加热反应、蒸馏</td><td style="text-align:left;">圆底/平底/蒸馏烧瓶区分</td></tr><tr><td style="text-align:center;">锥形瓶</td><td style="text-align:left;">滴定、接收液体</td><td style="text-align:left;">加热时垫石棉网</td></tr><tr><td style="text-align:center;">蒸发皿</td><td style="text-align:left;">蒸发浓缩</td><td style="text-align:left;">直接加热，用坩埚钳夹取</td></tr><tr><td style="text-align:center;">坩埚</td><td style="text-align:left;">高温灼烧固体</td><td style="text-align:left;">配合泥三角、三脚架使用</td></tr><tr><td style="text-align:center;">容量瓶</td><td style="text-align:left;">配制一定体积溶液</td><td style="text-align:left;">不能加热，不能长期储存</td></tr><tr><td style="text-align:center;">滴定管</td><td style="text-align:left;">精确滴加液体</td><td style="text-align:left;">酸式/碱式区分，使用前洗涤+润洗</td></tr><tr><td style="text-align:center;">分液漏斗</td><td style="text-align:left;">分液、萃取</td><td style="text-align:left;">检漏，上层上口出，下层下口出</td></tr></tbody></table><h3 id="_1-2-基本操作" tabindex="-1">1.2 基本操作 <a class="header-anchor" href="#_1-2-基本操作" aria-label="Permalink to &quot;1.2 基本操作&quot;">​</a></h3><p><strong>药品取用</strong>：</p><ul><li>固体：药匙、镊子（块状用镊子）</li><li>液体：倾倒法、滴加法（胶头滴管垂直悬空）</li><li>原则：不触（不接触药品）、不闻（不把鼻子凑近闻）、不尝</li></ul><p><strong>加热操作</strong>：</p><ul><li>直接加热：试管、蒸发皿、坩埚</li><li>间接加热（垫石棉网）：烧杯、烧瓶、锥形瓶</li><li>水浴加热：温度不超过100℃，受热均匀</li></ul><p><strong>溶解与搅拌</strong>：</p><ul><li>固体溶解：搅拌加速，必要时加热</li><li>液体稀释：浓硫酸沿器壁慢慢注入水中，不断搅拌</li></ul><hr><h2 id="第二章-物质的分离与提纯" tabindex="-1">第二章：物质的分离与提纯 <a class="header-anchor" href="#第二章-物质的分离与提纯" aria-label="Permalink to &quot;第二章：物质的分离与提纯&quot;">​</a></h2><h3 id="_2-1-分离方法速查表" tabindex="-1">2.1 分离方法速查表 <a class="header-anchor" href="#_2-1-分离方法速查表" aria-label="Permalink to &quot;2.1 分离方法速查表&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">方法</th><th style="text-align:left;">适用范围</th><th style="text-align:left;">仪器</th><th style="text-align:left;">关键操作</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>过滤</strong></td><td style="text-align:left;">固液分离</td><td style="text-align:left;">漏斗、烧杯、玻璃棒</td><td style="text-align:left;">一贴二低三靠</td></tr><tr><td style="text-align:center;"><strong>蒸发</strong></td><td style="text-align:left;">从溶液中获得固体</td><td style="text-align:left;">蒸发皿、酒精灯、玻璃棒</td><td style="text-align:left;">不断搅拌，余热蒸干</td></tr><tr><td style="text-align:center;"><strong>结晶</strong></td><td style="text-align:left;">溶解度随温度变化大的物质</td><td style="text-align:left;">烧杯、酒精灯</td><td style="text-align:left;">蒸发浓缩、冷却结晶、过滤洗涤</td></tr><tr><td style="text-align:center;"><strong>蒸馏</strong></td><td style="text-align:left;">沸点不同的液体混合物</td><td style="text-align:left;">蒸馏烧瓶、冷凝管、接收器</td><td style="text-align:left;">温度计位置，冷水下进上出</td></tr><tr><td style="text-align:center;"><strong>萃取</strong></td><td style="text-align:left;">溶质在互不相溶的溶剂中溶解度不同</td><td style="text-align:left;">分液漏斗</td><td style="text-align:left;">充分振荡，静置分层</td></tr><tr><td style="text-align:center;"><strong>分液</strong></td><td style="text-align:left;">互不相溶的液体分离</td><td style="text-align:left;">分液漏斗</td><td style="text-align:left;">下层下口出，上层上口出</td></tr><tr><td style="text-align:center;"><strong>升华</strong></td><td style="text-align:left;">受热易升华的物质（如I₂）</td><td style="text-align:left;">烧杯、圆底烧瓶</td><td style="text-align:left;">加热使升华，冷却凝华</td></tr></tbody></table><h3 id="_2-2-过滤操作要点" tabindex="-1">2.2 过滤操作要点 <a class="header-anchor" href="#_2-2-过滤操作要点" aria-label="Permalink to &quot;2.2 过滤操作要点&quot;">​</a></h3><p><strong>一贴</strong>：滤纸紧贴漏斗内壁 <strong>二低</strong>：滤纸边缘低于漏斗边缘；液面低于滤纸边缘 <strong>三靠</strong>：烧杯紧靠玻璃棒；玻璃棒轻靠三层滤纸处；漏斗下端紧靠烧杯内壁</p><h3 id="_2-3-蒸馏操作要点" tabindex="-1">2.3 蒸馏操作要点 <a class="header-anchor" href="#_2-3-蒸馏操作要点" aria-label="Permalink to &quot;2.3 蒸馏操作要点&quot;">​</a></h3><p><strong>温度计位置</strong>：水银球位于蒸馏烧瓶支管口处（测蒸气温度） <strong>冷凝水方向</strong>：下口进，上口出（逆流原理，冷凝效果好） <strong>加碎瓷片</strong>：防止液体暴沸</p><h3 id="_2-4-萃取与分液" tabindex="-1">2.4 萃取与分液 <a class="header-anchor" href="#_2-4-萃取与分液" aria-label="Permalink to &quot;2.4 萃取与分液&quot;">​</a></h3><p><strong>萃取剂选择原则</strong>：</p><ol><li>与原溶剂互不相溶</li><li>溶质在萃取剂中的溶解度远大于在原溶剂中</li><li>萃取剂与溶质不发生化学反应</li></ol><p><strong>常见萃取例子</strong>：</p><ul><li>用CCl₄萃取溴水中的Br₂</li><li>用苯萃取碘水中的I₂</li></ul><hr><h2 id="第三章-常见气体的制备" tabindex="-1">第三章：常见气体的制备 <a class="header-anchor" href="#第三章-常见气体的制备" aria-label="Permalink to &quot;第三章：常见气体的制备&quot;">​</a></h2><h3 id="_3-1-气体发生装置" tabindex="-1">3.1 气体发生装置 <a class="header-anchor" href="#_3-1-气体发生装置" aria-label="Permalink to &quot;3.1 气体发生装置&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">装置类型</th><th style="text-align:left;">适用反应</th><th style="text-align:left;">例子</th></tr></thead><tbody><tr><td style="text-align:center;">固+固，加热</td><td style="text-align:left;">制O₂、NH₃</td><td style="text-align:left;">KClO₃制O₂、NH₄Cl+Ca(OH)₂制NH₃</td></tr><tr><td style="text-align:center;">固+液，不加热</td><td style="text-align:left;">制H₂、CO₂、C₂H₂</td><td style="text-align:left;">Zn+H₂SO₄制H₂、CaCO₃+HCl制CO₂</td></tr><tr><td style="text-align:center;">固+液，加热</td><td style="text-align:left;">制Cl₂、C₂H₄</td><td style="text-align:left;">MnO₂+HCl制Cl₂</td></tr></tbody></table><h3 id="_3-2-常见气体制备" tabindex="-1">3.2 常见气体制备 <a class="header-anchor" href="#_3-2-常见气体制备" aria-label="Permalink to &quot;3.2 常见气体制备&quot;">​</a></h3><p><strong>氧气（O₂）</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>2KClO₃ =△= 2KCl + 3O₂↑（MnO₂催化）</span></span>
<span class="line"><span>2KMnO₄ =△= K₂MnO₄ + MnO₂ + O₂↑</span></span>
<span class="line"><span>2H₂O₂ =MnO₂= 2H₂O + O₂↑</span></span></code></pre></div><ul><li>收集：排水法或向上排空气法</li></ul><p><strong>氢气（H₂）</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Zn + H₂SO₄ = ZnSO₄ + H₂↑</span></span></code></pre></div><ul><li>收集：排水法或向下排空气法</li><li>验纯：点燃前必须验纯</li></ul><p><strong>二氧化碳（CO₂）</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CaCO₃ + 2HCl = CaCl₂ + H₂O + CO₂↑</span></span></code></pre></div><ul><li>收集：向上排空气法（能溶于水，不能用排水法）</li><li>验满：燃着的木条放在瓶口，熄灭则满</li></ul><p><strong>氨气（NH₃）</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>2NH₄Cl + Ca(OH)₂ =△= CaCl₂ + 2NH₃↑ + 2H₂O</span></span></code></pre></div><ul><li>收集：向下排空气法（极易溶于水，密度小于空气）</li><li>验满：湿润的红色石蕊试纸放在瓶口，变蓝则满</li></ul><p><strong>氯气（Cl₂）</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MnO₂ + 4HCl(浓) =△= MnCl₂ + Cl₂↑ + 2H₂O</span></span></code></pre></div><ul><li>收集：向上排空气法或排饱和食盐水法</li><li>尾气处理：用NaOH溶液吸收</li></ul><h3 id="_3-3-气体净化与干燥" tabindex="-1">3.3 气体净化与干燥 <a class="header-anchor" href="#_3-3-气体净化与干燥" aria-label="Permalink to &quot;3.3 气体净化与干燥&quot;">​</a></h3><p><strong>除杂原则</strong>：不引入新杂质，不减少被净化气体</p><p><strong>常见净化装置</strong>：</p><ul><li>洗气瓶（长进短出）：除去气体中的杂质气体</li><li>干燥管/U形管：装固体干燥剂</li></ul><p><strong>常见干燥剂</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:center;">干燥剂</th><th style="text-align:left;">可干燥气体</th><th style="text-align:left;">不能干燥气体</th></tr></thead><tbody><tr><td style="text-align:center;">浓H₂SO₄</td><td style="text-align:left;">H₂、O₂、CO₂、Cl₂、SO₂</td><td style="text-align:left;">NH₃（反应）、H₂S（反应）</td></tr><tr><td style="text-align:center;">无水CaCl₂</td><td style="text-align:left;">H₂、O₂、N₂、HCl</td><td style="text-align:left;">NH₃（络合）</td></tr><tr><td style="text-align:center;">碱石灰</td><td style="text-align:left;">H₂、O₂、NH₃</td><td style="text-align:left;">CO₂、SO₂、Cl₂、HCl（反应）</td></tr><tr><td style="text-align:center;">P₂O₅</td><td style="text-align:left;">H₂、O₂、CO₂、HCl</td><td style="text-align:left;">NH₃（反应）</td></tr></tbody></table><hr><h2 id="第四章-物质的检验与鉴别" tabindex="-1">第四章：物质的检验与鉴别 <a class="header-anchor" href="#第四章-物质的检验与鉴别" aria-label="Permalink to &quot;第四章：物质的检验与鉴别&quot;">​</a></h2><h3 id="_4-1-阳离子检验" tabindex="-1">4.1 阳离子检验 <a class="header-anchor" href="#_4-1-阳离子检验" aria-label="Permalink to &quot;4.1 阳离子检验&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">离子</th><th style="text-align:left;">检验方法</th><th style="text-align:left;">现象</th></tr></thead><tbody><tr><td style="text-align:center;">H⁺</td><td style="text-align:left;">紫色石蕊试液</td><td style="text-align:left;">变红</td></tr><tr><td style="text-align:center;">NH₄⁺</td><td style="text-align:left;">加NaOH溶液，加热，湿润红色石蕊试纸检验</td><td style="text-align:left;">产生刺激性气味气体，试纸变蓝</td></tr><tr><td style="text-align:center;">Fe²⁺</td><td style="text-align:left;">加KSCN溶液，再加氯水</td><td style="text-align:left;">先无明显现象，后变血红色</td></tr><tr><td style="text-align:center;">Fe³⁺</td><td style="text-align:left;">加KSCN溶液</td><td style="text-align:left;">变血红色</td></tr><tr><td style="text-align:center;">Cu²⁺</td><td style="text-align:left;">加NaOH溶液</td><td style="text-align:left;">产生蓝色沉淀</td></tr><tr><td style="text-align:center;">Ag⁺</td><td style="text-align:left;">加稀盐酸或可溶性氯化物</td><td style="text-align:left;">产生白色沉淀，不溶于稀HNO₃</td></tr><tr><td style="text-align:center;">Ba²⁺</td><td style="text-align:left;">加稀H₂SO₄或可溶性硫酸盐</td><td style="text-align:left;">产生白色沉淀，不溶于稀HNO₃</td></tr></tbody></table><h3 id="_4-2-阴离子检验" tabindex="-1">4.2 阴离子检验 <a class="header-anchor" href="#_4-2-阴离子检验" aria-label="Permalink to &quot;4.2 阴离子检验&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">离子</th><th style="text-align:left;">检验方法</th><th style="text-align:left;">现象</th></tr></thead><tbody><tr><td style="text-align:center;">OH⁻</td><td style="text-align:left;">紫色石蕊试液/酚酞</td><td style="text-align:left;">变蓝/变红</td></tr><tr><td style="text-align:center;">Cl⁻</td><td style="text-align:left;">加AgNO₃溶液，再加稀HNO₃</td><td style="text-align:left;">产生白色沉淀，不溶于稀HNO₃</td></tr><tr><td style="text-align:center;">Br⁻</td><td style="text-align:left;">加AgNO₃溶液，再加稀HNO₃</td><td style="text-align:left;">产生淡黄色沉淀</td></tr><tr><td style="text-align:center;">I⁻</td><td style="text-align:left;">加AgNO₃溶液，再加稀HNO₃</td><td style="text-align:left;">产生黄色沉淀</td></tr><tr><td style="text-align:center;">SO₄²⁻</td><td style="text-align:left;">先加稀盐酸，再加BaCl₂溶液</td><td style="text-align:left;">产生白色沉淀</td></tr><tr><td style="text-align:center;">CO₃²⁻</td><td style="text-align:left;">加稀盐酸，气体通入澄清石灰水</td><td style="text-align:left;">产生无色无味气体，石灰水变浑浊</td></tr><tr><td style="text-align:center;">SO₃²⁻</td><td style="text-align:left;">加稀盐酸，气体通入品红溶液</td><td style="text-align:left;">产生刺激性气味气体，品红褪色</td></tr></tbody></table><h3 id="_4-3-气体检验" tabindex="-1">4.3 气体检验 <a class="header-anchor" href="#_4-3-气体检验" aria-label="Permalink to &quot;4.3 气体检验&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">气体</th><th style="text-align:left;">检验方法</th><th style="text-align:left;">现象</th></tr></thead><tbody><tr><td style="text-align:center;">O₂</td><td style="text-align:left;">带火星的木条</td><td style="text-align:left;">木条复燃</td></tr><tr><td style="text-align:center;">H₂</td><td style="text-align:left;">点燃，在火焰上方罩冷而干燥的烧杯</td><td style="text-align:left;">淡蓝色火焰，烧杯内壁有水珠</td></tr><tr><td style="text-align:center;">CO₂</td><td style="text-align:left;">通入澄清石灰水</td><td style="text-align:left;">石灰水变浑浊</td></tr><tr><td style="text-align:center;">Cl₂</td><td style="text-align:left;">湿润的淀粉-KI试纸</td><td style="text-align:left;">试纸变蓝</td></tr><tr><td style="text-align:center;">NH₃</td><td style="text-align:left;">湿润的红色石蕊试纸</td><td style="text-align:left;">试纸变蓝</td></tr><tr><td style="text-align:center;">SO₂</td><td style="text-align:left;">通入品红溶液，加热</td><td style="text-align:left;">品红褪色，加热恢复红色</td></tr></tbody></table><hr><h2 id="第五章-实验探究题" tabindex="-1">第五章：实验探究题 <a class="header-anchor" href="#第五章-实验探究题" aria-label="Permalink to &quot;第五章：实验探究题&quot;">​</a></h2><h3 id="_5-1-实验探究题结构" tabindex="-1">5.1 实验探究题结构 <a class="header-anchor" href="#_5-1-实验探究题结构" aria-label="Permalink to &quot;5.1 实验探究题结构&quot;">​</a></h3><p><strong>常见题型</strong>：</p><ol><li><strong>假设验证型</strong>：给出假设，设计实验验证</li><li><strong>方案评价型</strong>：评价给定实验方案的优缺点</li><li><strong>实验设计型</strong>：自主设计实验方案</li></ol><p><strong>答题模板</strong>：</p><p><strong>提出假设</strong>：</p><ul><li>假设一：...</li><li>假设二：...</li><li>假设三：...</li></ul><p><strong>设计实验</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:center;">步骤</th><th style="text-align:left;">操作</th><th style="text-align:left;">预期现象</th><th style="text-align:left;">结论</th></tr></thead><tbody><tr><td style="text-align:center;">1</td><td style="text-align:left;">...</td><td style="text-align:left;">...</td><td style="text-align:left;">...</td></tr><tr><td style="text-align:center;">2</td><td style="text-align:left;">...</td><td style="text-align:left;">...</td><td style="text-align:left;">...</td></tr></tbody></table><p><strong>得出结论</strong>：根据实验现象，支持或否定假设</p><h3 id="_5-2-实验方案评价角度" tabindex="-1">5.2 实验方案评价角度 <a class="header-anchor" href="#_5-2-实验方案评价角度" aria-label="Permalink to &quot;5.2 实验方案评价角度&quot;">​</a></h3><p><strong>科学性</strong>：原理是否正确，操作是否可行 <strong>安全性</strong>：是否有安全隐患 <strong>简约性</strong>：步骤是否简单，试剂是否易得 <strong>经济性</strong>：成本是否合理 <strong>环保性</strong>：是否产生污染，如何处理</p><h3 id="_5-3-常见答题规范" tabindex="-1">5.3 常见答题规范 <a class="header-anchor" href="#_5-3-常见答题规范" aria-label="Permalink to &quot;5.3 常见答题规范&quot;">​</a></h3><p><strong>描述现象要全面</strong>：</p><ul><li>颜色变化：...色→...色</li><li>沉淀：产生...色沉淀</li><li>气体：产生...色气体/产生气泡</li><li>温度：放热/吸热</li></ul><p><strong>解释原因要逻辑清晰</strong>：</p><ol><li>发生了什么反应（化学方程式）</li><li>产生了什么物质/变化</li><li>导致什么现象</li></ol><hr><h2 id="faq-常见错误与解答" tabindex="-1">FAQ（常见错误与解答） <a class="header-anchor" href="#faq-常见错误与解答" aria-label="Permalink to &quot;FAQ（常见错误与解答）&quot;">​</a></h2><h3 id="q1-实验操作题总是丢分怎么办" tabindex="-1">Q1：实验操作题总是丢分怎么办？ <a class="header-anchor" href="#q1-实验操作题总是丢分怎么办" aria-label="Permalink to &quot;Q1：实验操作题总是丢分怎么办？&quot;">​</a></h3><p><strong>A</strong>：</p><ol><li>熟记「基本操作要点」（如过滤的一贴二低三靠）</li><li>理解每一步操作的目的（为什么这样做）</li><li>注意细节（如温度计位置、冷凝水方向）</li></ol><h3 id="q2-物质检验题总是漏检或错检怎么办" tabindex="-1">Q2：物质检验题总是漏检或错检怎么办？ <a class="header-anchor" href="#q2-物质检验题总是漏检或错检怎么办" aria-label="Permalink to &quot;Q2：物质检验题总是漏检或错检怎么办？&quot;">​</a></h3><p><strong>A</strong>：</p><ol><li>熟记「检验顺序」（先检验干扰性强的）</li><li>注意「排除干扰」（如检验Cl⁻前要排除SO₄²⁻干扰）</li><li>记住特征现象（颜色变化、沉淀、气体）</li></ol><h3 id="q3-实验探究题不知道怎么设计实验怎么办" tabindex="-1">Q3：实验探究题不知道怎么设计实验怎么办？ <a class="header-anchor" href="#q3-实验探究题不知道怎么设计实验怎么办" aria-label="Permalink to &quot;Q3：实验探究题不知道怎么设计实验怎么办？&quot;">​</a></h3><p><strong>A</strong>：</p><ol><li>使用「对照实验」思想（控制变量）</li><li>使用「假设-验证」框架</li><li>多参考课本实验的设计思路</li><li>记住常见答题模板</li></ol><h3 id="q4-气体制备实验装置连接顺序是什么" tabindex="-1">Q4：气体制备实验装置连接顺序是什么？ <a class="header-anchor" href="#q4-气体制备实验装置连接顺序是什么" aria-label="Permalink to &quot;Q4：气体制备实验装置连接顺序是什么？&quot;">​</a></h3><p><strong>A</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>发生装置 → 净化装置 → 干燥装置 → 收集装置 → 尾气处理装置</span></span></code></pre></div><ul><li>净化：除去杂质气体</li><li>干燥：除去水蒸气</li><li>注意：净化和干燥顺序（先除杂后干燥）</li></ul><hr><h2 id="文档信息" tabindex="-1">文档信息 <a class="header-anchor" href="#文档信息" aria-label="Permalink to &quot;文档信息&quot;">​</a></h2><p><strong>文档编号</strong>: Chem-Learn-Detail-005<br><strong>板块</strong>: 化学实验<br><strong>版本</strong>: V1.0<br><strong>编制日期</strong>: 2026-04-05<br><strong>配套文档</strong>: Chem-Learn-Method-001</p><hr><p><em>化学实验是理论与实践的结合，重视课本实验，理解操作原理。</em></p>`,104)])])}const c=e(i,[["render",s]]);export{y as __pageData,c as default};
